11	export const quote = (items: Array<{ type: string }>, customer: unknown, contractNumber: number): number => {
12	  if (items.length === 0) return PROCESSING_FEE;
13	  const basePremium = BASE_PREMIUMS[items[0].type] ?? 0;
14	  return Math.ceil(basePremium + basePremium / 10) + PROCESSING_FEE;
15	};
